import React, { useEffect, useState, useRef } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { Bell, ChevronDown, User as UserIcon, Heart, Search, LogOut, Plus, Menu, X, ShoppingCart } from 'lucide-react';
import { useApp } from '../store';
import SideDrawer from './SideDrawer';

const Navbar = () => {
  const { user, isAuthenticated, notifications, markNotificationRead, clearNotifications, logout, openCart, cart } = useApp();
  const [notifOpen, setNotifOpen] = useState(false);
  const [profileOpen, setProfileOpen] = useState(false);
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  const location = useLocation();
  const navigate = useNavigate();
  const notifRef = useRef<HTMLDivElement>(null);
  const profileRef = useRef<HTMLDivElement>(null);

  // Scroll Logic for Sticky Background
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
        setScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notifRef.current && !notifRef.current.contains(event.target as Node)) setNotifOpen(false);
      if (profileRef.current && !profileRef.current.contains(event.target as Node)) setProfileOpen(false);
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const handleSearch = (e: React.FormEvent) => {
      e.preventDefault();
      if(searchQuery.trim()) {
          navigate(`/search?q=${encodeURIComponent(searchQuery)}`);
      }
  };

  const myNotifications = notifications.filter(n => n.userId === user?.id).sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  const unreadCount = myNotifications.filter(n => !n.isRead).length;

  const handleLogout = () => {
      logout();
      navigate('/');
      setProfileOpen(false);
  };

  // Reusable Notification Dropdown
  const renderNotifications = () => (
      <div className="absolute right-0 mt-3 w-80 glass border border-white/10 rounded-2xl shadow-2xl overflow-hidden z-50 animate-slide-up origin-top-right bg-[#1a1d24]">
        <div className="p-4 border-b border-white/5 flex justify-between items-center bg-white/5">
            <h4 className="text-sm font-bold text-white">Bildirişlər</h4>
            <button onClick={clearNotifications} className="text-xs text-primary hover:text-primary-dark">Təmizlə</button>
        </div>
        <div className="max-h-64 overflow-y-auto">
            {myNotifications.length === 0 ? <div className="p-8 text-center text-gray-500 text-sm">Bildiriş yoxdur.</div> : myNotifications.map(notif => (
                <div key={notif.id} onClick={() => markNotificationRead(notif.id)} className={`p-4 border-b border-white/5 hover:bg-white/5 cursor-pointer transition-colors ${!notif.isRead ? 'bg-primary/5' : ''}`}>
                    <p className={`text-sm ${!notif.isRead ? 'font-semibold text-white' : 'text-gray-400'}`}>{notif.title}</p>
                    <p className="text-xs text-gray-500 mt-1">{notif.message}</p>
                </div>
            ))}
        </div>
    </div>
  );

  return (
    <>
    <SideDrawer isOpen={drawerOpen} onClose={() => setDrawerOpen(false)} />

    <nav 
        className={`fixed top-0 left-0 w-full z-50 transition-all duration-300 border-b 
        ${scrolled 
            ? 'bg-[#0F1115]/95 backdrop-blur-xl border-white/10 shadow-2xl py-2' 
            : 'bg-[#0F1115]/50 backdrop-blur-md border-transparent py-3 md:py-4'}`}
    >
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">

        {/* DESKTOP LAYOUT */}
        <div className="hidden md:flex items-center justify-between gap-8">

            {/* Left: Logo & Links */}
            <div className="flex items-center gap-8 shrink-0">
                <Link to="/" className="flex items-center gap-2 group">
                    <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-primary to-secondary flex items-center justify-center text-white font-bold text-xl shadow-lg shadow-primary/20 group-hover:scale-105 transition-transform">D</div>
                    <span className="text-2xl font-bold text-white tracking-tight">GAME<span className="text-primary font-light">PAY</span></span>
                </Link>

                <div className="flex items-center gap-6">
                    <Link to="/" className="text-sm font-bold text-gray-300 hover:text-white transition-colors">Ana Səhifə</Link>
                    <Link to="/categories" className="text-sm font-bold text-gray-300 hover:text-white transition-colors">Kateqoriyalar</Link>
                    <Link to="/page/haqqimizda" className="text-sm font-bold text-gray-300 hover:text-white transition-colors">Haqqımızda</Link>
                    <Link to="/contact" className="text-sm font-bold text-gray-300 hover:text-white transition-colors">Əlaqə</Link>
                </div>
            </div>

            {/* Middle: Search */}
            <div className="flex-1 max-w-xl">
                <form onSubmit={handleSearch} className="relative w-full group">
                    <input 
                        type="text" 
                        placeholder="Məhsul axtar..." 
                        className="w-full bg-white/5 border border-white/10 rounded-xl py-2.5 pl-11 pr-4 text-sm text-white focus:bg-black/40 focus:border-primary transition-all duration-300 outline-none placeholder-gray-500 shadow-inner"
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                    />
                    <Search className="absolute left-3.5 top-2.5 w-5 h-5 text-gray-500 group-focus-within:text-primary transition-colors" />
                </form>
            </div>

            {/* Right: Actions */}
            <div className="flex items-center gap-4 shrink-0">
                {/* Cart Icon for Desktop */}
                <button onClick={openCart} className="relative p-2.5 bg-white/5 hover:bg-white/10 rounded-xl text-gray-400 hover:text-white transition-colors border border-white/5 group">
                    <ShoppingCart className="w-5 h-5 group-hover:text-primary transition-colors" />
                    {cart.length > 0 && <span className="absolute -top-1 -right-1 w-5 h-5 bg-primary text-white text-[10px] font-bold rounded-full flex items-center justify-center border-2 border-[#0F1115]">{cart.length}</span>}
                </button>

                {isAuthenticated ? (
                    <>
                        <div className="flex items-center gap-3 bg-white/5 border border-white/10 pl-4 pr-1 py-1 rounded-xl">
                            <span className="text-sm font-mono font-bold text-white">{user?.balance.toFixed(2)} <span className="text-primary">₼</span></span>
                            <button onClick={() => navigate('/balance')} className="bg-primary hover:bg-primary-dark text-white p-1.5 rounded-lg transition-colors shadow-lg shadow-primary/20">
                                <Plus className="w-4 h-4" />
                            </button>
                        </div>

                        <div className="relative" ref={notifRef}>
                            <button onClick={() => setNotifOpen(!notifOpen)} className="relative p-2.5 bg-white/5 hover:bg-white/10 rounded-xl text-gray-400 hover:text-white transition-colors border border-white/5">
                                <Bell className="w-5 h-5" />
                                {unreadCount > 0 && <span className="absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full animate-pulse"></span>}
                            </button>
                            {notifOpen && renderNotifications()}
                        </div>

                        <div className="relative" ref={profileRef}>
                            <button onClick={() => setProfileOpen(!profileOpen)} className="flex items-center gap-2 pl-1 pr-3 py-1 rounded-xl bg-white/5 border border-white/10 hover:bg-white/10 transition-all">
                                <div className="h-9 w-9 rounded-lg bg-gradient-to-tr from-primary to-secondary flex items-center justify-center text-white font-bold shadow-lg">
                                    {user?.avatar ? <img src={user.avatar} className="w-full h-full object-cover rounded-lg"/> : user?.name.charAt(0)}
                                </div>
                                <ChevronDown className={`w-4 h-4 text-gray-400 transition-transform ${profileOpen ? 'rotate-180' : ''}`} />
                            </button>
                            {profileOpen && (
                                <div className="absolute right-0 mt-4 w-56 glass border border-white/10 rounded-2xl shadow-2xl p-2 z-50 animate-slide-up origin-top-right bg-[#1a1d24]">
                                    <Link to="/profile" onClick={() => setProfileOpen(false)} className="flex items-center gap-2 px-3 py-2 text-sm text-gray-300 hover:text-white hover:bg-white/10 rounded-lg transition-colors">
                                        <UserIcon className="w-4 h-4" /> Profil
                                    </Link>
                                    <Link to="/profile" onClick={() => setProfileOpen(false)} className="flex items-center gap-2 px-3 py-2 text-sm text-gray-300 hover:text-white hover:bg-white/10 rounded-lg transition-colors">
                                        <Heart className="w-4 h-4" /> İstək siyahısı
                                    </Link>
                                    {user?.role === 'admin' && (
                                        <Link to="/admin" onClick={() => setProfileOpen(false)} className="flex items-center gap-2 px-3 py-2 text-sm text-red-400 hover:text-red-300 hover:bg-red-500/10 rounded-lg transition-colors">
                                            Admin Panel
                                        </Link>
                                    )}
                                    <div className="h-px bg-white/5 my-2"></div>
                                    <button onClick={handleLogout} className="w-full flex items-center gap-2 px-3 py-2 text-sm text-red-400 hover:text-red-300 hover:bg-red-500/10 rounded-lg transition-colors">
                                        <LogOut className="w-4 h-4" /> Çıxış
                                    </button>
                                </div>
                            )}
                        </div>
                    </>
                ) : (
                    <div className="flex items-center gap-3">
                        <Link to="/auth" className="text-white font-bold hover:text-primary transition-colors text-sm">Daxil Ol</Link>
                        <Link to="/auth" className="bg-white text-black px-5 py-2.5 rounded-xl font-bold hover:bg-gray-200 transition-colors shadow-lg shadow-white/10 text-sm">Qeydiyyat</Link>
                    </div>
                )}
            </div>
        </div>

        {/* MOBILE LAYOUT (Text Only / Minimal) */}
        <div className="md:hidden flex flex-col gap-2">
            <div className="flex items-center justify-between">
                {/* Text Menu Button */}
                <button 
                    onClick={() => setDrawerOpen(true)} 
                    className="text-white font-bold text-sm bg-white/5 px-3 py-2 rounded-lg border border-white/10"
                >
                    MENU
                </button>

                {/* Logo */}
                <Link to="/" className="flex items-center gap-1">
                    <span className="font-black text-white text-xl tracking-tight">GAME<span className="text-primary">PAY</span></span>
                </Link>

                {/* Right: Auth or Text Icon */}
                {isAuthenticated ? (
                     <div className="relative" ref={notifRef}>
                        <button onClick={() => setNotifOpen(!notifOpen)} className="text-white font-bold text-xs bg-white/5 px-3 py-2 rounded-lg border border-white/10 flex items-center gap-1">
                             BİLDİRİŞ 
                             {unreadCount > 0 && <span className="w-2 h-2 bg-red-500 rounded-full"></span>}
                        </button>
                        {notifOpen && renderNotifications()}
                     </div>
                ) : (
                    <Link to="/auth" className="text-primary font-bold text-sm">GİRİŞ</Link>
                )}
            </div>

            {/* Search - Full Width */}
            <form onSubmit={handleSearch} className="relative w-full">
                <input 
                    type="text" 
                    placeholder="Məhsul axtar..." 
                    className="w-full bg-white/5 border border-white/10 rounded-lg py-2 px-4 text-sm text-white focus:border-primary outline-none"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                />
            </form>
        </div>

      </div>
    </nav>
    </>
  );
};

export default Navbar;

import React from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { Home, LayoutGrid, ShoppingCart, User, MessageCircle } from 'lucide-react';
import { useApp } from '../store';

const BottomNav = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const { user, cart, openCart } = useApp();

  if (location.pathname.startsWith('/admin') || location.pathname === '/auth') {
      return null;
  }

  const isActive = (path: string) => location.pathname === path;

  const handleProfileClick = () => {
      if (user) {
          navigate('/profile');
      } else {
          navigate('/auth');
      }
  };

  return (
    <div className="md:hidden fixed bottom-0 left-0 w-full bg-[#0F1115]/95 backdrop-blur-xl border-t border-white/10 z-[60] pb-safe pt-2 h-[80px] shadow-[0_-5px_20px_rgba(0,0,0,0.5)]">
        <div className="grid grid-cols-5 h-full relative items-start pt-2">

            {/* 1. Home */}
            <button onClick={() => navigate('/')} className="flex flex-col items-center justify-center gap-1 group">
                <Home className={`w-6 h-6 transition-all duration-300 group-active:scale-90 ${isActive('/') ? 'text-primary fill-primary/20' : 'text-gray-500'}`} strokeWidth={isActive('/') ? 2.5 : 2} />
                <span className={`text-[10px] transition-colors ${isActive('/') ? 'text-white font-bold' : 'text-gray-500'}`}>Ana Səhifə</span>
            </button>

            {/* 2. Categories - UPDATED LABEL */}
            <button onClick={() => navigate('/categories')} className="flex flex-col items-center justify-center gap-1 group">
                <LayoutGrid className={`w-6 h-6 transition-all duration-300 group-active:scale-90 ${isActive('/categories') ? 'text-primary fill-primary/20' : 'text-gray-500'}`} strokeWidth={isActive('/categories') ? 2.5 : 2} />
                <span className={`text-[10px] transition-colors ${isActive('/categories') ? 'text-white font-bold' : 'text-gray-500'}`}>Kateqoriyalar</span>
            </button>

            {/* 3. CART (Enhanced Floating Effect) */}
            <div className="relative flex justify-center -top-8">
                <button 
                    onClick={openCart} 
                    className="absolute bg-gradient-to-tr from-primary to-secondary w-16 h-16 rounded-full border-[6px] border-[#0F1115] shadow-[0_0_20px_rgba(139,92,246,0.6)] transform transition-transform active:scale-90 hover:scale-110 flex items-center justify-center z-10 group"
                >
                    <ShoppingCart className="w-7 h-7 text-white drop-shadow-md" strokeWidth={2.5} />
                    {cart.length > 0 && (
                        <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] font-bold w-5 h-5 rounded-full flex items-center justify-center border-2 border-[#0F1115] animate-bounce">
                            {cart.length}
                        </span>
                    )}
                    {/* Inner Pulse Ring */}
                    <div className="absolute inset-0 rounded-full border border-white/30 animate-ping opacity-20"></div>
                </button>
                <span className="absolute -bottom-8 text-[11px] font-bold text-white drop-shadow-[0_0_5px_rgba(0,0,0,0.8)]">Səbət</span>
            </div>

            {/* 4. Support */}
            <button onClick={() => navigate('/contact')} className="flex flex-col items-center justify-center gap-1 group">
                <MessageCircle className={`w-6 h-6 transition-all duration-300 group-active:scale-90 ${isActive('/contact') ? 'text-primary fill-primary/20' : 'text-gray-500'}`} strokeWidth={isActive('/contact') ? 2.5 : 2} />
                <span className={`text-[10px] transition-colors ${isActive('/contact') ? 'text-white font-bold' : 'text-gray-500'}`}>Dəstək</span>
            </button>

            {/* 5. Profile */}
            <button onClick={handleProfileClick} className="flex flex-col items-center justify-center gap-1 group">
                <User className={`w-6 h-6 transition-all duration-300 group-active:scale-90 ${isActive('/profile') ? 'text-primary fill-primary/20' : 'text-gray-500'}`} strokeWidth={isActive('/profile') ? 2.5 : 2} />
                <span className={`text-[10px] transition-colors ${isActive('/profile') ? 'text-white font-bold' : 'text-gray-500'}`}>Profil</span>
            </button>
        </div>
    </div>
  );
};

export default BottomNav;

import React, { useState, useRef, useEffect } from 'react';
import { useApp } from '../store';
import { Order, OrderStatus, ProductType, Product, PromoCode, PaymentMethod, Blog, Agreement, HeroSlide, Page } from '../types';
import { 
  BarChart3, ShoppingBag, Package, Users, Settings, LogOut, 
  Plus, Trash2, Search, Edit3, X, Check, Eye, Wallet, 
  Database, Infinity, Menu, FileText, MessageSquare, CreditCard, Globe, Shield, Image as ImageIcon, Save, Star, Layout, Link as LinkIcon, Info, Tag, Upload, Monitor, File, Gift
} from 'lucide-react';
import { useNavigate } from 'react-router-dom';

// --- REUSABLE IMAGE INPUT COMPONENT ---
const ImageInput = ({ label, value, onChange, placeholder = "Şəkil" }: { label: string, value: string, onChange: (val: string) => void, placeholder?: string }) => {
    const [mode, setMode] = useState<'url' | 'upload'>('url');
    const fileRef = useRef<HTMLInputElement>(null);

    const handleUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            const url = URL.createObjectURL(e.target.files[0]);
            onChange(url);
        }
    };

    return (
        <div className="space-y-2">
            <label className="block text-xs uppercase font-bold text-gray-400">{label}</label>

            <div className="flex bg-surfaceHighlight rounded-t-xl overflow-hidden border border-white/10 border-b-0">
                <button 
                    onClick={() => setMode('url')} 
                    className={`flex-1 py-2 text-xs font-bold flex items-center justify-center gap-2 transition-colors ${mode === 'url' ? 'bg-primary text-white' : 'text-gray-400 hover:text-white hover:bg-white/5'}`}
                >
                    <LinkIcon className="w-3 h-3" /> Link (URL)
                </button>
                <button 
                    onClick={() => setMode('upload')} 
                    className={`flex-1 py-2 text-xs font-bold flex items-center justify-center gap-2 transition-colors ${mode === 'upload' ? 'bg-primary text-white' : 'text-gray-400 hover:text-white hover:bg-white/5'}`}
                >
                    <Monitor className="w-3 h-3" /> PC-dən Yüklə
                </button>
            </div>

            <div className="relative">
                {mode === 'url' ? (
                    <div className="relative">
                        <input 
                            className="w-full bg-surfaceHighlight border border-white/10 rounded-b-xl p-3 text-white focus:border-primary outline-none text-sm" 
                            placeholder="https://example.com/image.jpg" 
                            value={value.startsWith('blob:') ? '' : value} 
                            onChange={e => onChange(e.target.value)} 
                        />
                        {value && !value.startsWith('blob:') && (
                            <div className="absolute right-3 top-3 w-6 h-6 rounded overflow-hidden border border-white/20">
                                <img src={value} className="w-full h-full object-cover" />
                            </div>
                        )}
                    </div>
                ) : (
                    <div 
                        onClick={() => fileRef.current?.click()}
                        className="w-full bg-surfaceHighlight border-2 border-dashed border-white/10 rounded-b-xl h-24 flex flex-col items-center justify-center cursor-pointer hover:border-primary/50 transition-colors group relative overflow-hidden"
                    >
                        {value ? (
                            <img src={value} className="absolute inset-0 w-full h-full object-cover opacity-50 group-hover:opacity-30 transition-opacity" />
                        ) : null}
                        <div className="relative z-10 flex flex-col items-center">
                            <Upload className="w-5 h-5 text-gray-400 group-hover:text-white mb-1" />
                            <span className="text-xs text-gray-500 group-hover:text-white font-bold">Şəkil Seçmək üçün Toxun</span>
                        </div>
                        <input type="file" ref={fileRef} hidden accept="image/*" onChange={handleUpload} />
                    </div>
                )}
            </div>

            {value && (
                <div className="mt-2 text-xs text-green-400 flex items-center gap-1">
                    <Check className="w-3 h-3" /> Şəkil seçildi
                </div>
            )}
        </div>
    );
};

const Admin = () => {
  const navigate = useNavigate();
  const { 
    user, orders, completeOrder, cancelOrder, products, 
    siteSettings, updateSiteSettings,
    categories, addCategory, deleteCategory, togglePopularCategory,
    addProduct, deleteProduct, togglePopularProduct,
    addAgreement, deleteAgreement,
    blogs, addBlog, deleteBlog,
    paymentMethods, addPaymentMethod, deletePaymentMethod, updatePaymentMethod,
    comments, deleteComment, logout,
    usersList, toggleUserBan, updateUserBalance,
    promoCodes, addPromoCode, deletePromoCode,
    stocks, addStock, deleteStock, activityLogs,
    heroSlides, addHeroSlide, deleteHeroSlide,
    pages, addPage, updatePage, deletePage
  } = useApp();

  const [activeTab, setActiveTab] = useState<'dashboard' | 'orders' | 'products' | 'categories' | 'stock' | 'users' | 'content' | 'pages' | 'finance' | 'settings'>('dashboard');
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  // --- STATE MANAGEMENT ---

  // Orders
  const [deliveryModal, setDeliveryModal] = useState<{orderId: string, productTitle: string} | null>(null);
  const [deliveryContent, setDeliveryContent] = useState('');
  const [orderFilter, setOrderFilter] = useState<'ALL' | OrderStatus>('ALL');

  // Products
  const [productView, setProductView] = useState<'list' | 'add'>('list');
  const [productSearch, setProductSearch] = useState('');
  const [isEditingProd, setIsEditingProd] = useState(false);
  const [productForm, setProductForm] = useState<Partial<Product>>({
    title: '', categoryId: '', subCategory: '', price: 0, costPrice: 0, discountPercent: 0, type: ProductType.LICENSE_KEY, image: '', description: '', requiresInput: false, durationDays: 0, isLifetime: false, isPopular: false
  });

  // Categories
  const [catForm, setCatForm] = useState<{name: string, image: string, subCategoriesInput: string}>({ name: '', image: '', subCategoriesInput: '' });

  // Stock
  const [stockProduct, setStockProduct] = useState('');
  const [stockInput, setStockInput] = useState('');

  // Users
  const [userSearch, setUserSearch] = useState('');

  // Pages
  const [isEditingPage, setIsEditingPage] = useState(false);
  const [pageForm, setPageForm] = useState<Partial<Page>>({ title: '', slug: '', content: '', category: 'corporate', isActive: true });

  // Settings
  const [generalForm, setGeneralForm] = useState(siteSettings);
  const [slideForm, setSlideForm] = useState<Partial<HeroSlide>>({ image: '', title: '', subtitle: '', desc: '', btnText: 'İndi Al', link: '/' });

  if (!user || user.role !== 'admin') {
    return (
        <div className="min-h-screen flex items-center justify-center bg-background text-red-500 font-bold text-2xl">
            Access Denied
        </div>
    );
  }

  // --- HELPERS ---

  const handleLogout = () => { logout(); navigate('/'); };

  const handleDelete = (type: string, id: string) => {
      if(window.confirm(`Silmək istədiyinizə əminsiniz?`)) {
          switch(type) {
              case 'product': deleteProduct(id); break;
              case 'category': deleteCategory(id); break;
              case 'promo': deletePromoCode(id); break;
              case 'comment': deleteComment(id); break;
              case 'stock': deleteStock(id); break;
              case 'blog': deleteBlog(id); break;
              case 'rule': deleteAgreement(id); break;
              case 'payment': deletePaymentMethod(id); break;
              case 'slide': deleteHeroSlide(id); break;
              case 'page': deletePage(id); break;
          }
      }
  };

  // Category Logic
  const handleSaveCategory = () => {
      if(!catForm.name) return;
      const subCats = catForm.subCategoriesInput.split(',').map(s => s.trim()).filter(s => s.length > 0);
      addCategory({
          id: `cat-${Date.now()}`,
          name: catForm.name,
          image: catForm.image,
          subCategories: subCats,
          isPopular: false
      });
      setCatForm({ name: '', image: '', subCategoriesInput: '' });
      alert("Kateqoriya əlavə edildi.");
  };

  // Product Logic
  const handleEditProduct = (p: Product) => {
      setProductForm(p);
      setIsEditingProd(true);
      setProductView('add');
  };

  const handleSaveProduct = () => {
      if(!productForm.title || !productForm.price || !productForm.categoryId) {
          alert("Zəhmət olmasa vacib xanaları doldurun.");
          return;
      }
      const newProduct = { ...productForm, id: isEditingProd ? productForm.id! : `p-${Date.now()}` } as Product;
      if(isEditingProd) deleteProduct(productForm.id!);
      addProduct(newProduct);
      setProductView('list');
      setProductForm({ title: '', categoryId: '', subCategory: '', price: 0, costPrice: 0, discountPercent: 0, type: ProductType.LICENSE_KEY, image: '', description: '', requiresInput: false, durationDays: 0, isLifetime: false, isPopular: false });
      setIsEditingProd(false);
  };

  // Page Logic
  const handleSavePage = () => {
      if(!pageForm.title || !pageForm.content) return;
      const slug = pageForm.slug || pageForm.title!.toLowerCase().replace(/ /g, '-').replace(/[^\w-]+/g, '');

      const newPage: Page = {
          id: pageForm.id || `pg-${Date.now()}`,
          title: pageForm.title!,
          slug: slug,
          content: pageForm.content!,
          category: pageForm.category || 'corporate',
          isActive: pageForm.isActive ?? true
      };

      if (isEditingPage && pageForm.id) {
          updatePage(pageForm.id, newPage);
      } else {
          addPage(newPage);
      }
      setPageForm({ title: '', slug: '', content: '', category: 'corporate', isActive: true });
      setIsEditingPage(false);
  };

  const handleEditPage = (page: Page) => {
      setPageForm(page);
      setIsEditingPage(true);
  };

  // Stock Logic
  const handleAddStock = () => {
      if(!stockProduct || !stockInput) return;
      const codes = stockInput.split('\n').filter(c => c.trim().length > 0);
      addStock(stockProduct, codes);
      setStockInput('');
      alert(`${codes.length} ədəd kod əlavə olundu.`);
  };

  // Order Logic
  const confirmDelivery = () => {
      if(deliveryModal) {
          completeOrder(deliveryModal.orderId, deliveryContent);
          setDeliveryModal(null);
          setDeliveryContent('');
      }
  };

  // Settings Logic
  const saveGeneralSettings = () => {
      updateSiteSettings(generalForm);
      alert("Ayarlar yadda saxlanıldı!");
  };

  const handleSaveSlide = () => {
      if(!slideForm.image || !slideForm.title) return;
      addHeroSlide({ ...slideForm, id: `slide-${Date.now()}` } as HeroSlide);
      setSlideForm({ image: '', title: '', subtitle: '', desc: '', btnText: 'İndi Al', link: '/' });
  };

  // Menu Items
  const menuItems = [
      { id: 'dashboard', label: 'Dashboard', icon: BarChart3 },
      { id: 'orders', label: 'Sifarişlər', icon: ShoppingBag, badge: orders.filter(o => o.status === 'PENDING').length },
      { id: 'categories', label: 'Kateqoriyalar', icon: Layout },
      { id: 'products', label: 'Məhsullar', icon: Package },
      { id: 'stock', label: 'Stok', icon: Database },
      { id: 'pages', label: 'Səhifələr (CMS)', icon: File },
      { id: 'users', label: 'İstifadəçilər', icon: Users },
      { id: 'settings', label: 'Ayarlar & Dizayn', icon: Settings },
  ];

  const filteredOrders = orders.filter(o => orderFilter === 'ALL' || o.status === orderFilter);

  // Get Subcategories for product form
  const selectedCatSubCats = categories.find(c => c.id === productForm.categoryId)?.subCategories || [];

  return (
    <div className="min-h-screen bg-background text-white flex flex-col md:flex-row font-sans">

      {/* SIDEBAR */}
      <div className={`fixed inset-y-0 left-0 z-50 w-64 glass border-r border-white/10 transform ${mobileMenuOpen ? 'translate-x-0' : '-translate-x-full'} md:translate-x-0 transition-transform duration-200 ease-in-out flex flex-col`}>
          <div className="p-6 border-b border-white/10 flex justify-between items-center">
              <span className="text-xl font-black text-white tracking-widest uppercase">Admin</span>
              <button onClick={() => setMobileMenuOpen(false)} className="md:hidden"><X /></button>
          </div>

          <nav className="flex-1 overflow-y-auto p-4 space-y-2">
              {menuItems.map(item => (
                  <button
                      key={item.id}
                      onClick={() => { setActiveTab(item.id as any); setMobileMenuOpen(false); }}
                      className={`w-full flex items-center justify-between px-4 py-3 rounded-xl transition-all ${activeTab === item.id ? 'bg-primary text-white shadow-lg shadow-primary/20' : 'text-gray-400 hover:bg-white/5 hover:text-white'}`}
                  >
                      <div className="flex items-center gap-3">
                          <item.icon className="w-5 h-5" />
                          <span className="font-medium">{item.label}</span>
                      </div>
                      {item.badge ? <span className="bg-red-500 text-white text-[10px] font-bold px-2 py-0.5 rounded-full">{item.badge}</span> : null}
                  </button>
              ))}
          </nav>

          <div className="p-4 border-t border-white/10">
              <button onClick={handleLogout} className="w-full flex items-center gap-3 px-4 py-3 text-red-400 hover:bg-red-500/10 rounded-xl transition-colors font-bold">
                  <LogOut className="w-5 h-5" /> Çıxış
              </button>
          </div>
      </div>

      {/* MOBILE HEADER */}
      <div className="md:hidden glass border-b border-white/10 p-4 flex justify-between items-center sticky top-0 z-40">
          <span className="font-bold text-lg">Admin Panel</span>
          <button onClick={() => setMobileMenuOpen(true)}><Menu /></button>
      </div>

      {/* MAIN CONTENT */}
      <div className="flex-1 md:ml-64 p-4 md:p-8 overflow-y-auto bg-background">

          {/* ORDERS */}
          {activeTab === 'orders' && (
              <div className="space-y-6 animate-fade-in">
                  <h2 className="text-3xl font-bold mb-4">Sifariş İdarəçiliyi</h2>
                  <div className="flex gap-2 mb-4 overflow-x-auto pb-2">
                      {['ALL', 'PENDING', 'PROCESSING', 'COMPLETED', 'CANCELLED'].map(status => (
                          <button 
                              key={status} 
                              onClick={() => setOrderFilter(status as any)}
                              className={`px-4 py-2 rounded-lg text-sm font-bold border transition-colors ${orderFilter === status ? 'bg-primary text-white border-primary' : 'bg-transparent border-white/20 text-gray-400 hover:text-white'}`}
                          >
                              {status}
                          </button>
                      ))}
                  </div>

                  <div className="space-y-4">
                      {filteredOrders.length === 0 ? <p className="text-gray-500 text-center py-10">Sifariş tapılmadı.</p> : filteredOrders.map(order => (
                          <div key={order.id} className="glass-card p-6 rounded-2xl border border-white/10 flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                              <div className="flex-1">
                                  <div className="flex items-center gap-3 mb-2">
                                      <h3 className="font-bold text-white text-lg">{order.productTitle}</h3>
                                      <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase ${
                                          order.status === 'COMPLETED' ? 'bg-green-500/20 text-green-400' : 
                                          order.status === 'PENDING' ? 'bg-yellow-500/20 text-yellow-400' : 'bg-red-500/20 text-red-400'
