const Navbar = () => {
  const { user, isAuthenticated, notifications, markNotificationRead, clearNotifications, logout } = useApp();
  const [notifOpen, setNotifOpen] = useState(false);
  const [profileOpen, setProfileOpen] = useState(false);
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  const location = useLocation();
  const navigate = useNavigate();
  const notifRef = useRef<HTMLDivElement>(null);
  const profileRef = useRef<HTMLDivElement>(null);

  // Scroll Logic for Sticky Background
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
        setScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notifRef.current && !notifRef.current.contains(event.target as Node)) setNotifOpen(false);
      if (profileRef.current && !profileRef.current.contains(event.target as Node)) setProfileOpen(false);
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const handleSearch = (e: React.FormEvent) => {
      e.preventDefault();
      if(searchQuery.trim()) {
          navigate(`/search?q=${encodeURIComponent(searchQuery)}`);
      }
  };

  const myNotifications = notifications.filter(n => n.userId === user?.id).sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  const unreadCount = myNotifications.filter(n => !n.isRead).length;

  const handleLogout = () => {
      logout();
      navigate('/');
      setProfileOpen(false);
  };

  const handleNotificationClick = (id: string) => {
      markNotificationRead(id);
  };

  // Reusable Notification Dropdown
  const renderNotifications = () => (
      <div className="absolute right-0 mt-3 w-80 glass border border-white/10 rounded-2xl shadow-2xl overflow-hidden z-50 animate-slide-up origin-top-right bg-[#1a1d24]">
        <div className="p-4 border-b border-white/5 flex justify-between items-center bg-white/5">
            <h4 className="text-sm font-bold text-white">Bildirişlər</h4>
            <button onClick={(e) => { e.stopPropagation(); clearNotifications(); }} className="text-xs text-primary hover:text-primary-dark font-bold">Təmizlə</button>
        </div>
        <div className="max-h-64 overflow-y-auto">
            {myNotifications.length === 0 ? <div className="p-8 text-center text-gray-500 text-sm">Bildiriş yoxdur.</div> : myNotifications.map(notif => (
                <div key={notif.id} onClick={() => handleNotificationClick(notif.id)} className={`p-4 border-b border-white/5 hover:bg-white/5 cursor-pointer transition-colors ${!notif.isRead ? 'bg-primary/10 border-l-2 border-primary' : 'opacity-70'}`}>
                    <p className={`text-sm ${!notif.isRead ? 'font-bold text-white' : 'text-gray-400'}`}>{notif.title}</p>
                    <p className="text-xs text-gray-500 mt-1">{notif.message}</p>
                </div>
            ))}
        </div>
    </div>
  );

  const navLinkClass = "px-4 py-2 rounded-xl text-sm font-bold transition-all duration-300 bg-white/5 text-gray-300 hover:text-white hover:bg-primary/20 hover:shadow-[0_0_15px_rgba(139,92,246,0.2)]";
  const activeNavLinkClass = "px-4 py-2 rounded-xl text-sm font-bold bg-primary text-white shadow-[0_0_15px_rgba(139,92,246,0.4)]";

  return (
    <>
    <SideDrawer isOpen={drawerOpen} onClose={() => setDrawerOpen(false)} />

    <nav 
        className={`fixed top-0 left-0 w-full z-50 transition-all duration-300 border-b 
        ${scrolled 
            ? 'bg-[#0F1115]/95 backdrop-blur-xl border-white/10 shadow-2xl py-2' 
            : 'bg-[#0F1115]/50 backdrop-blur-md border-transparent py-3 md:py-4'}`}
    >
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">

        {/* DESKTOP LAYOUT */}
        <div className="hidden md:flex items-center justify-between gap-8">

            {/* Left: Logo & Links */}
            <div className="flex items-center gap-6 shrink-0">
                <Link to="/" className="flex items-center gap-2 group mr-4">
                    <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-primary to-secondary flex items-center justify-center text-white font-bold text-xl shadow-lg shadow-primary/20 group-hover:scale-105 transition-transform">D</div>
                    <span className="text-2xl font-bold text-white tracking-tight">GAME<span className="text-primary font-light">PAY</span></span>
                </Link>

                <div className="flex items-center gap-3">
                    <Link to="/" className={location.pathname === '/' ? activeNavLinkClass : navLinkClass}>Ana Səhifə</Link>
                    <Link to="/categories" className={location.pathname === '/categories' ? activeNavLinkClass : navLinkClass}>Kateqoriyalar</Link>
                    <Link to="/page/haqqimizda" className={location.pathname === '/page/haqqimizda' ? activeNavLinkClass : navLinkClass}>Haqqımızda</Link>
                    <Link to="/contact" className={location.pathname === '/contact' ? activeNavLinkClass : navLinkClass}>Əlaqə</Link>
                </div>
            </div>

            {/* Middle: Search */}
            <div className="flex-1 max-w-md">
                <form onSubmit={handleSearch} className="relative w-full group">
                    <input 
                        type="text" 
                        placeholder="Məhsul axtar..." 
                        className="w-full bg-white/5 border border-white/10 rounded-xl py-2.5 pl-11 pr-4 text-sm text-white focus:bg-black/40 focus:border-primary transition-all duration-300 outline-none placeholder-gray-500 shadow-inner"
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                    />
                    <Search className="absolute left-3.5 top-2.5 w-5 h-5 text-gray-500 group-focus-within:text-primary transition-colors" />
                </form>
            </div>

            {/* Right: Actions */}
            <div className="flex items-center gap-4 shrink-0">

                {isAuthenticated ? (
                    <>
                        {/* Balance Display */}
                        <div className="flex items-center gap-3 bg-white/5 border border-white/10 pl-4 pr-1 py-1 rounded-xl">
                            <span className="text-sm font-mono font-bold text-white">{user?.balance.toFixed(2)} <span className="text-primary">₼</span></span>
                            <button onClick={() => navigate('/balance')} className="bg-primary hover:bg-primary-dark text-white p-1.5 rounded-lg transition-colors shadow-lg shadow-primary/20">
                                <Plus className="w-4 h-4" />
                            </button>
                        </div>

                        <div className="relative" ref={notifRef}>
                            <button onClick={() => setNotifOpen(!notifOpen)} className="relative p-2.5 bg-white/5 hover:bg-white/10 rounded-xl text-gray-400 hover:text-white transition-colors border border-white/5">
                                <Bell className="w-5 h-5" />
                                {unreadCount > 0 && <span className="absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full animate-pulse shadow-[0_0_10px_rgba(239,68,68,0.5)]"></span>}
                            </button>
                            {notifOpen && renderNotifications()}
                        </div>

                        <div className="relative" ref={profileRef}>
                            <button onClick={() => setProfileOpen(!profileOpen)} className="flex items-center gap-2 pl-1 pr-3 py-1 rounded-xl bg-white/5 border border-white/10 hover:bg-white/10 transition-all">
                                <div className="h-9 w-9 rounded-lg bg-gradient-to-tr from-primary to-secondary flex items-center justify-center text-white font-bold shadow-lg">
                                    {user?.avatar ? <img src={user.avatar} className="w-full h-full object-cover rounded-lg"/> : user?.name.charAt(0).toUpperCase()}
                                </div>
                                <ChevronDown className={`w-4 h-4 text-gray-400 transition-transform ${profileOpen ? 'rotate-180' : ''}`} />
                            </button>
                            {profileOpen && (
                                <div className="absolute right-0 mt-4 w-56 glass border border-white/10 rounded-2xl shadow-2xl p-2 z-50 animate-slide-up origin-top-right bg-[#1a1d24]">
                                    <Link to="/profile" onClick={() => setProfileOpen(false)} className="flex items-center gap-2 px-3 py-2 text-sm text-gray-300 hover:text-white hover:bg-white/10 rounded-lg transition-colors">
                                        <UserIcon className="w-4 h-4" /> Profil
                                    </Link>
                                    <Link to="/profile" onClick={() => setProfileOpen(false)} className="flex items-center gap-2 px-3 py-2 text-sm text-gray-300 hover:text-white hover:bg-white/10 rounded-lg transition-colors">
                                        <Heart className="w-4 h-4" /> İstək siyahısı
                                    </Link>
                                    {user?.role === 'admin' && (
                                        <Link to="/admin" onClick={() => setProfileOpen(false)} className="flex items-center gap-2 px-3 py-2 text-sm text-red-400 hover:text-red-300 hover:bg-red-500/10 rounded-lg transition-colors">
                                            Admin Panel
                                        </Link>
                                    )}
                                    <div className="h-px bg-white/5 my-2"></div>
                                    <button onClick={handleLogout} className="w-full flex items-center gap-2 px-3 py-2 text-sm text-red-400 hover:text-red-300 hover:bg-red-500/10 rounded-lg transition-colors">
                                        <LogOut className="w-4 h-4" /> Çıxış
                                    </button>
                                </div>
                            )}
                        </div>
                    </>
                ) : (
                    <div className="flex items-center gap-3">
                        <Link to="/auth" className="text-white font-bold hover:text-primary transition-colors text-sm px-4 py-2">Daxil Ol</Link>
                        <Link to="/auth" className="bg-white text-black px-5 py-2.5 rounded-xl font-bold hover:bg-gray-200 transition-colors shadow-lg shadow-white/10 text-sm">Qeydiyyat</Link>
                    </div>
                )}
            </div>
        </div>

        {/* MOBILE LAYOUT */}
        <div className="md:hidden flex flex-col gap-3">
            <div className="flex items-center justify-between">
                {/* Menu Icon */}
                <button 
                    onClick={() => setDrawerOpen(true)} 
                    className="text-white p-2"
                >
                    <Menu className="w-6 h-6" />
                </button>

                {/* Logo */}
                <Link to="/" className="flex items-center gap-1">
                    <span className="font-black text-white text-xl tracking-tight">GAME<span className="text-primary">PAY</span></span>
                </Link>

                {/* Right: Auth or Notification */}
                <div className="flex items-center gap-3">
                    {isAuthenticated ? (
                         <>
                            {/* Mobile Balance */}
                            <div onClick={() => navigate('/balance')} className="flex items-center gap-1 bg-white/5 px-2 py-1 rounded-lg border border-white/10 cursor-pointer">
                                <span className="text-xs font-mono font-bold text-white">{user?.balance.toFixed(2)} <span className="text-primary">₼</span></span>
                            </div>

                            <div className="relative" ref={notifRef}>
                                <button onClick={() => setNotifOpen(!notifOpen)} className="text-white p-2 relative">
                                     <Bell className="w-6 h-6" />
                                     {unreadCount > 0 && <span className="absolute top-1 right-1 w-2.5 h-2.5 bg-red-500 rounded-full border border-[#0F1115]"></span>}
                                </button>
                                {notifOpen && renderNotifications()}
                            </div>
                         </>
                    ) : (
                        <Link to="/auth" className="text-white p-2">
                            <UserIcon className="w-6 h-6" />
                        </Link>
                    )}
                </div>
            </div>

            {/* Search - Full Width */}
            <form onSubmit={handleSearch} className="relative w-full">
                <input 
                    type="text" 
                    placeholder="Məhsul axtar..." 
                    className="w-full bg-white/5 border border-white/10 rounded-lg py-2.5 pl-10 px-4 text-sm text-white focus:border-primary outline-none"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                />
                <Search className="absolute left-3 top-2.5 w-4 h-4 text-gray-500" />
            </form>
        </div>

      </div>
    </nav>
    </>
  );
};

export default Navbar;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useApp } from '../store';
import ProductCard from '../components/ProductCard';
import { ArrowLeft, Search, Filter, ArrowDownUp, Layers, ChevronRight, Grid } from 'lucide-react';

const CategoryPage = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { categories, products } = useApp();

  const [search, setSearch] = useState('');
  const [sortOption, setSortOption] = useState<'default' | 'price-asc' | 'price-desc' | 'name-asc'>('default');

  // Step State: If string is set, we show products for that sub-category. If null, we show sub-category list.
  const [selectedSubCat, setSelectedSubCat] = useState<string | null>(null);

  const category = categories.find(c => c.id === id);

  // Logic: Does this category have sub-categories defined?
  // We use the predefined subCategories from the category object.
  const subCategories = category?.subCategories || [];
  const hasSubCategories = subCategories.length > 0;

  // Determine which View to show
  // Step 2 View: Show Sub-Category Cards IF category has subs AND none is selected yet.
  // Step 3 View: Show Products IF category has NO subs OR one is selected.
  const showSubCategorySelection = hasSubCategories && selectedSubCat === null;

  // Filter Products based on current state
  const categoryProducts = products.filter(p => {
      // Must match main category
      if (p.categoryId !== id) return false;

      // If we are in "Show Products" mode and there are sub-categories, filter by selected
      if (!showSubCategorySelection && hasSubCategories && selectedSubCat) {
          return p.subCategory === selectedSubCat;
      }

      return true;
  });

  // Apply Search & Sort
  const filteredProducts = categoryProducts
    .filter(p => p.title.toLowerCase().includes(search.toLowerCase()))
    .sort((a, b) => {
        if (sortOption === 'price-asc') return a.price - b.price;
        if (sortOption === 'price-desc') return b.price - a.price;
        if (sortOption === 'name-asc') return a.title.localeCompare(b.title);
        return 0; 
    });

  // Handle Back Navigation (Hierarchy)
  const handleBack = () => {
      if (!showSubCategorySelection && hasSubCategories && selectedSubCat) {
          // If viewing products of a sub-category, go back to sub-category selection
          setSelectedSubCat(null);
          setSearch(''); 
      } else {
          // If at selection screen or root category, go home
          navigate('/');
      }
  };

  if (!category) {
      return (
        <div className="min-h-screen bg-gaming-dark flex items-center justify-center">
            <div className="text-center">
                <h2 className="text-2xl font-bold text-white mb-2">Kateqoriya Tapılmadı</h2>
                <button onClick={() => navigate('/')} className="text-gaming-neon hover:underline">Ana Səhifəyə Qayıt</button>
            </div>
        </div>
      );
  }

  return (
    <div className="min-h-screen bg-gaming-dark pb-20 pt-6 px-4">
        <div className="max-w-7xl mx-auto">

            {/* 1. Header Navigation Bar */}
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
                <button onClick={handleBack} className="flex items-center text-gray-400 hover:text-white group transition-colors w-fit">
                    <div className="bg-slate-800 p-2 rounded-full mr-2 group-hover:bg-slate-700 transition-colors">
                        <ArrowLeft className="w-5 h-5" />
                    </div>
                    <div className="flex flex-col items-start">
                        <span className="text-xs text-gray-500 font-bold uppercase tracking-wider">Geri Qayıt</span>
                        <span className="text-sm font-bold text-white group-hover:text-primary transition-colors">
                            {showSubCategorySelection ? 'Ana Səhifə' : (hasSubCategories ? 'Növ Seçimi' : 'Ana Səhifə')}
                        </span>
                    </div>
                </button>

                {/* Breadcrumbs / Title */}
                <div className="flex items-center gap-2 text-sm md:text-lg font-bold text-gray-500">
                    <span className={showSubCategorySelection ? "text-white" : ""}>{category.name}</span>
                    {selectedSubCat && (
                        <>
                            <ChevronRight className="w-4 h-4" />
                            <span className="text-gaming-neon">{selectedSubCat}</span>
                        </>
                    )}
                </div>
            </div>

            {/* STEP 2: SUB-CATEGORY SELECTION VIEW */}
            {showSubCategorySelection && (
                <div className="animate-fade-in">
                    <div className="text-center mb-10">
                        <h1 className="text-3xl md:text-5xl font-black text-white uppercase tracking-tighter mb-4">
                            Xidmət <span className="text-transparent bg-clip-text bg-gradient-to-r from-primary to-secondary">Növünü Seçin</span>
                        </h1>
                        <p className="text-gray-400 text-lg">Davam etmək üçün aşağıdakı seçimlərdən birinə klikləyin.</p>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        {subCategories.map((sub, index) => (
                            <div 
                                key={index}
                                onClick={() => setSelectedSubCat(sub)}
                                className="group relative h-48 md:h-64 rounded-3xl overflow-hidden cursor-pointer border border-white/10 hover:border-gaming-neon transition-all duration-300 shadow-2xl"
                            >
                                {/* Background Image with Blur */}
                                <div className="absolute inset-0">
                                    <img 
                                        src={category.image} 
                                        alt={sub} 
                                        className="w-full h-full object-cover opacity-60 group-hover:scale-105 transition-transform duration-700 filter blur-sm group-hover:blur-0" 
                                    />
                                    <div className="absolute inset-0 bg-gradient-to-t from-black via-black/50 to-transparent"></div>
                                </div>

                                {/* Content */}
                                <div className="absolute inset-0 flex flex-col justify-end p-8">
                                    <div className="transform translate-y-2 group-hover:translate-y-0 transition-transform duration-300">
                                        <div className="flex items-center gap-3 mb-2">
                                            <span className="bg-gaming-neon text-black text-xs font-bold px-2 py-1 rounded uppercase tracking-wider">Seçim {index + 1}</span>
                                        </div>
                                        <h2 className="text-2xl md:text-4xl font-black text-white uppercase italic leading-none mb-2 group-hover:text-primary transition-colors">
                                            {sub}
                                        </h2>
                                        <p className="text-gray-400 text-sm opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex items-center gap-1">
                                            Məhsullara bax <ChevronRight className="w-4 h-4"/>
                                        </p>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* STEP 3: PRODUCTS VIEW */}
            {!showSubCategorySelection && (
                <div className="animate-fade-in">

                    {/* Header Banner (Compact) */}
                    <div className="relative rounded-2xl overflow-hidden mb-8 h-40 border border-gray-800 shadow-lg group">
                        {category.image && (
                            <img src={category.image} className="w-full h-full object-cover opacity-40" alt={category.name} />
                        )}
                        <div className="absolute inset-0 bg-gradient-to-r from-black via-black/80 to-transparent flex items-center p-8">
                             <div>
                                 <h1 className="text-2xl md:text-4xl font-black text-white uppercase italic mb-1">
                                     {selectedSubCat || category.name}
                                 </h1>
                                 <p className="text-gray-400 text-sm">
                                    <span className="text-gaming-neon font-bold">{filteredProducts.length}</span> məhsul tapıldı
                                 </p>
                             </div>
                        </div>
                    </div>

                    {/* Toolbar: Search & Sort */}
                    <div className="bg-gaming-card border border-gray-800 rounded-2xl p-4 mb-8 sticky top-24 z-30 shadow-xl backdrop-blur-md bg-opacity-90">
                        <div className="flex flex-col md:flex-row gap-4 justify-between">
                            {/* Search */}
                            <div className="relative flex-1">
                                <Search className="absolute left-3 top-3.5 text-gray-500 w-5 h-5" />
                                <input 
                                    type="text" 
                                    placeholder="Məhsul axtar..."
                                    className="w-full bg-slate-900 border border-gray-700 rounded-xl pl-10 pr-4 py-3 text-white focus:border-gaming-neon focus:ring-1 focus:ring-gaming-neon outline-none transition-all placeholder-gray-500"
                                    value={search}
                                    onChange={e => setSearch(e.target.value)}
                                />
                            </div>

                            {/* Sort Dropdown */}
                            <div className="relative min-w-[200px]">
                                <div className="absolute left-3 top-3.5 pointer-events-none">
                                    <ArrowDownUp className="w-5 h-5 text-gray-500" />
                                </div>
                                <select 
                                    className="w-full appearance-none bg-slate-900 border border-gray-700 rounded-xl pl-10 pr-8 py-3 text-white focus:border-gaming-neon outline-none cursor-pointer"
                                    value={sortOption}
                                    onChange={(e) => setSortOption(e.target.value as any)}
                                >
                                    <option value="default">Sıralama: Varsayılan</option>
                                    <option value="price-asc">Qiymət: Ucuzdan Bahaya</option>
                                    <option value="price-desc">Qiymət: Bahadan Ucuza</option>
                                    <option value="name-asc">Ad: A-Z</option>
                                </select>
                                <div className="absolute right-3 top-4 pointer-events-none">
                                    <Filter className="w-4 h-4 text-gray-500" />
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Product Grid */}
                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                        {filteredProducts.map(product => (
                            <ProductCard key={product.id} product={product} />
                        ))}
                    </div>

                    {/* Empty State */}
                    {filteredProducts.length === 0 && (
                        <div className="text-center py-20 bg-slate-900/30 rounded-3xl border border-dashed border-gray-800">
                            <div className="bg-slate-800 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-4">
                                <Search className="w-8 h-8 text-gray-500"/>
                            </div>
                            <h3 className="text-xl font-bold text-white mb-2">Nəticə Tapılmadı</h3>
                            <p className="text-gray-500">Bu kateqoriyada hələ məhsul yoxdur və ya axtarışa uyğun gəlmir.</p>
                            <button onClick={() => setSearch('')} className="mt-4 text-gaming-neon font-bold hover:underline">Axtarışı Təmizlə</button>
                        </div>
                    )}
                </div>
            )}
        </div>
    </div>
  );
};

export default CategoryPage;

