import React, { useState } from 'react';
import { ShoppingCart, X, Trash2, Plus, Minus, ArrowRight, CreditCard, Wallet, Upload } from 'lucide-react';
import { useApp } from '../store';
import { useNavigate } from 'react-router-dom';

const CartWidget = () => {
  const { cart, updateCartQuantity, removeFromCart, isCartOpen, openCart, closeCart, placeOrder, paymentMethods, user, isAuthenticated } = useApp();
  const navigate = useNavigate();
  const [checkoutStep, setCheckoutStep] = useState<'cart' | 'payment'>('cart');
  const [selectedMethod, setSelectedMethod] = useState<string | 'BALANCE' | null>(null);
  const [receiptFile, setReceiptFile] = useState<File | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const subTotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  const handleCheckout = async () => {
     if(!isAuthenticated) {
         closeCart();
         navigate('/auth');
         return;
     }

     if(!selectedMethod) return;
     if (selectedMethod !== 'BALANCE' && !receiptFile) {
         alert("Zəhmət olmasa qəbz yükləyin.");
         return;
     }

     setIsSubmitting(true);
     const success = await placeOrder(selectedMethod, receiptFile || undefined);
     setIsSubmitting(false);

     if (success) {
        setCheckoutStep('cart');
        setSelectedMethod(null);
        setReceiptFile(null);
        closeCart();
        navigate('/profile'); 
     }
  };

  const reset = () => {
      setCheckoutStep('cart');
      setSelectedMethod(null);
      setReceiptFile(null);
      closeCart();
  }

  return (
    <>
      {/* Floating Trigger Button (Hidden on Mobile, Positioned left of Chat on Desktop) */}
      <button 
        onClick={openCart}
        className="hidden md:flex items-center justify-center fixed bottom-6 right-24 z-50 bg-gradient-to-tr from-primary to-secondary w-14 h-14 rounded-full shadow-[0_0_20px_rgba(139,92,246,0.5)] hover:scale-110 transition-transform active:scale-95 group"
      >
        <ShoppingCart className="w-7 h-7 text-white" />
        {cart.length > 0 && (
            <span className="absolute -top-1 -right-1 w-6 h-6 bg-red-500 text-white text-xs font-bold rounded-full flex items-center justify-center border-2 border-[#0F1115] animate-bounce">
                {cart.length}
            </span>
        )}
      </button>

      {/* Backdrop */}
      {isCartOpen && (
        <div className="fixed inset-0 bg-black/80 z-[60] backdrop-blur-sm transition-opacity" onClick={reset} />
      )}

      {/* Drawer */}
      <div className={`fixed top-0 right-0 h-full w-full sm:w-[420px] bg-surface/95 border-l border-white/10 z-[70] transform transition-transform duration-300 ease-out shadow-2xl flex flex-col backdrop-blur-xl ${isCartOpen ? 'translate-x-0' : 'translate-x-full'}`}>

         {/* Header */}
         <div className="p-6 border-b border-white/5 flex justify-between items-center bg-black/20">
            <h2 className="text-xl font-bold text-white flex items-center gap-3">
                {checkoutStep === 'cart' ? 'Səbətiniz' : 'Ödəniş'}
                {checkoutStep === 'cart' && <span className="bg-primary/20 text-primary text-xs px-2 py-1 rounded-full">{cart.length}</span>}
            </h2>
            <button onClick={reset} className="text-gray-400 hover:text-white p-2 hover:bg-white/5 rounded-full"><X /></button>
         </div>

         {/* Items */}
         <div className="flex-1 overflow-y-auto p-6 space-y-4">
            {cart.length === 0 ? (
                <div className="flex flex-col items-center justify-center h-full text-gray-500 space-y-4">
                    <div className="w-24 h-24 bg-surfaceHighlight rounded-full flex items-center justify-center mb-2">
                        <ShoppingCart className="w-10 h-10 opacity-30" />
                    </div>
                    <p className="font-medium text-lg">Səbətiniz boşdur</p>
                    <button onClick={reset} className="text-primary hover:text-white transition-colors">Alış-verişə davam et</button>
                </div>
            ) : checkoutStep === 'cart' ? (
                cart.map((item, index) => (
                    <div key={index} className="flex gap-4 p-4 rounded-2xl bg-surfaceHighlight/50 border border-white/5 hover:border-primary/30 transition-colors group">
                        <div className="w-20 h-20 rounded-xl overflow-hidden bg-black/50 shrink-0">
                            <img src={item.image} className="w-full h-full object-cover group-hover:scale-105 transition-transform" alt={item.title} />
                        </div>
                        <div className="flex-1 flex flex-col justify-between">
                            <div>
                                <h4 className="font-bold text-white text-sm line-clamp-1">{item.title}</h4>
                                {item.userInput && <p className="text-xs text-gray-400 mt-1">{item.userInput}</p>}
                            </div>

                            <div className="flex items-center justify-between mt-3">
                                <div className="text-white font-bold">{item.price.toFixed(2)} <span className="text-primary text-xs">₼</span></div>

                                <div className="flex items-center gap-3">
                                    <div className="flex items-center bg-black/30 rounded-lg p-0.5">
                                        <button onClick={() => updateCartQuantity(index, -1)} className="p-1.5 text-gray-400 hover:text-white"><Minus className="w-3 h-3"/></button>
                                        <span className="text-xs font-bold w-6 text-center text-white">{item.quantity}</span>
                                        <button onClick={() => updateCartQuantity(index, 1)} className="p-1.5 text-gray-400 hover:text-white"><Plus className="w-3 h-3"/></button>
                                    </div>
                                    <button onClick={() => removeFromCart(index)} className="text-gray-500 hover:text-red-500 transition-colors"><Trash2 className="w-4 h-4"/></button>
                                </div>
                            </div>
                        </div>
                    </div>
                ))
            ) : (
                <div className="space-y-6 animate-fade-in">
                    <div>
                        <h3 className="text-gray-400 uppercase text-xs font-bold mb-3">Ödəniş Metodu</h3>
                        <div className="space-y-2">
                            <button
                                onClick={() => setSelectedMethod('BALANCE')}
                                className={`w-full p-3 rounded-xl border flex items-center justify-between gap-2 transition-all text-sm text-left
                                    ${selectedMethod === 'BALANCE' 
                                    ? 'border-gaming-neon bg-gaming-neon/10' 
                                    : 'border-white/10 bg-slate-900 hover:bg-white/5'}`}
                            >
                                <div className="flex items-center gap-3">
                                    <div className="bg-black/40 p-2 rounded-lg"><Wallet className="w-4 h-4 text-purple-400" /></div>
                                    <span className="text-white font-bold">Balansdan Ödə</span>
                                </div>
                                <span className="text-gray-400 text-xs">{user?.balance.toFixed(2)} ₼</span>
                            </button>

                            {paymentMethods.filter(pm => pm.isActive).map(pm => (
                                <button
                                    key={pm.id}
                                    onClick={() => setSelectedMethod(pm.id)}
                                    className={`w-full p-3 rounded-xl border flex items-center gap-3 transition-all text-sm text-left
                                        ${selectedMethod === pm.id 
                                        ? 'border-gaming-neon bg-gaming-neon/10' 
                                        : 'border-white/10 bg-slate-900 hover:bg-white/5'}`}
                                >
                                    <div className="bg-black/40 p-2 rounded-lg"><CreditCard className="w-4 h-4 text-gray-400" /></div>
                                    <span className="text-white font-bold">{pm.name}</span>
                                </button>
                            ))}
                        </div>
                    </div>

                    {selectedMethod && selectedMethod !== 'BALANCE' && (
                        <div className="animate-fade-in">
                            <div className="bg-slate-900 p-4 rounded-xl text-sm border-l-4 border-primary mb-4">
                                <p className="text-gray-400 text-xs uppercase font-bold mb-1">Hesab:</p>
                                <p className="font-mono text-white mb-2">{paymentMethods.find(p=>p.id===selectedMethod)?.details}</p>
                                <p className="text-xs text-gray-500">{paymentMethods.find(p=>p.id===selectedMethod)?.instructions}</p>
                            </div>

                            <div className="relative border-2 border-dashed border-white/20 rounded-xl p-6 hover:bg-white/5 transition-colors text-center cursor-pointer">
                                <input type="file" accept="image/*" onChange={(e) => e.target.files && setReceiptFile(e.target.files[0])} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" />
                                <Upload className="w-6 h-6 text-gray-400 mx-auto mb-2" />
                                <p className="text-xs text-gray-300 font-bold">
                                    {receiptFile ? <span className="text-green-400">{receiptFile.name}</span> : "Qəbz yüklə"}
                                </p>
                            </div>
                        </div>
                    )}
                </div>
            )}
         </div>

         {/* Footer */}
         <div className="p-6 border-t border-white/5 bg-black/20">
            <div className="flex justify-between mb-6">
                <span className="text-gray-400">Cəmi Məbləğ</span>
                <span className="text-2xl font-bold text-white">{subTotal.toFixed(2)} <span className="text-primary">₼</span></span>
            </div>

            {checkoutStep === 'cart' ? (
                <button 
                    onClick={() => setCheckoutStep('payment')}
                    className="w-full bg-white text-black font-bold py-4 rounded-xl hover:bg-gray-200 transition-all flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed shadow-[0_0_20px_rgba(255,255,255,0.1)]"
                    disabled={cart.length === 0}
                >
                    Sifarişi Rəsmiləşdir <ArrowRight className="w-5 h-5" />
                </button>
            ) : (
                <div className="flex gap-2">
                    <button onClick={() => setCheckoutStep('cart')} className="px-4 py-4 rounded-xl bg-white/10 hover:bg-white/20 text-white font-bold">Geri</button>
                    <button 
                        onClick={handleCheckout}
                        disabled={!selectedMethod || (selectedMethod !== 'BALANCE' && !receiptFile) || isSubmitting}
                        className="flex-1 bg-green-600 text-white font-bold py-4 rounded-xl hover:bg-green-500 transition-all flex items-center justify-center gap-2 disabled:opacity-50"
                    >
                        {isSubmitting ? '...' : 'Təsdiqlə'} <ArrowRight className="w-5 h-5" />
                    </button>
                </div>
            )}
         </div>
      </div>
    </>
  );
};

export default CartWidget;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useApp } from '../store';
import ProductCard from '../components/ProductCard';
import { ArrowLeft, Search, Filter, ArrowDownUp, Layers, ChevronRight, Grid } from 'lucide-react';

const CategoryPage = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { categories, products } = useApp();

  const [search, setSearch] = useState('');
  const [sortOption, setSortOption] = useState<'default' | 'price-asc' | 'price-desc' | 'name-asc'>('default');

  // Step State: If string is set, we show products for that sub-category. If null, we show sub-category list.
  const [selectedSubCat, setSelectedSubCat] = useState<string | null>(null);

  const category = categories.find(c => c.id === id);

  // Logic: Does this category have sub-categories defined?
  // We use the predefined subCategories from the category object.
  const subCategories = category?.subCategories || [];
  const hasSubCategories = subCategories.length > 0;

  // Determine which View to show
  // Step 2 View: Show Sub-Category Cards IF category has subs AND none is selected yet.
  // Step 3 View: Show Products IF category has NO subs OR one is selected.
  const showSubCategorySelection = hasSubCategories && selectedSubCat === null;

  // Filter Products based on current state
  const categoryProducts = products.filter(p => {
      // Must match main category
      if (p.categoryId !== id) return false;

      // If we are in "Show Products" mode and there are sub-categories, filter by selected
      if (!showSubCategorySelection && hasSubCategories && selectedSubCat) {
          return p.subCategory === selectedSubCat;
      }

      return true;
  });

  // Apply Search & Sort
  const filteredProducts = categoryProducts
    .filter(p => p.title.toLowerCase().includes(search.toLowerCase()))
    .sort((a, b) => {
        if (sortOption === 'price-asc') return a.price - b.price;
        if (sortOption === 'price-desc') return b.price - a.price;
        if (sortOption === 'name-asc') return a.title.localeCompare(b.title);
        return 0; 
    });

  // Handle Back Navigation (Hierarchy)
  const handleBack = () => {
      if (!showSubCategorySelection && hasSubCategories && selectedSubCat) {
          // If viewing products of a sub-category, go back to sub-category selection
          setSelectedSubCat(null);
          setSearch(''); 
      } else {
          // If at selection screen or root category, go home
          navigate('/');
      }
  };

  if (!category) {
      return (
        <div className="min-h-screen bg-gaming-dark flex items-center justify-center">
            <div className="text-center">
                <h2 className="text-2xl font-bold text-white mb-2">Kateqoriya Tapılmadı</h2>
                <button onClick={() => navigate('/')} className="text-gaming-neon hover:underline">Ana Səhifəyə Qayıt</button>
            </div>
        </div>
      );
  }

  return (
    <div className="min-h-screen bg-gaming-dark pb-20 pt-6 px-4">
        <div className="max-w-7xl mx-auto">

            {/* 1. Header Navigation Bar */}
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
                <button onClick={handleBack} className="flex items-center text-gray-400 hover:text-white group transition-colors w-fit">
                    <div className="bg-slate-800 p-2 rounded-full mr-2 group-hover:bg-slate-700 transition-colors">
                        <ArrowLeft className="w-5 h-5" />
                    </div>
                    <div className="flex flex-col items-start">
                        <span className="text-xs text-gray-500 font-bold uppercase tracking-wider">Geri Qayıt</span>
                        <span className="text-sm font-bold text-white group-hover:text-primary transition-colors">
                            {showSubCategorySelection ? 'Ana Səhifə' : (hasSubCategories ? 'Növ Seçimi' : 'Ana Səhifə')}
                        </span>
                    </div>
                </button>

                {/* Breadcrumbs / Title */}
                <div className="flex items-center gap-2 text-sm md:text-lg font-bold text-gray-500">
                    <span className={showSubCategorySelection ? "text-white" : ""}>{category.name}</span>
                    {selectedSubCat && (
                        <>
                            <ChevronRight className="w-4 h-4" />
                            <span className="text-gaming-neon">{selectedSubCat}</span>
                        </>
                    )}
                </div>
            </div>

            {/* STEP 2: SUB-CATEGORY SELECTION VIEW */}
            {showSubCategorySelection && (
                <div className="animate-fade-in">
                    <div className="text-center mb-10">
                        <h1 className="text-3xl md:text-5xl font-black text-white uppercase tracking-tighter mb-4">
                            Xidmət <span className="text-transparent bg-clip-text bg-gradient-to-r from-primary to-secondary">Növünü Seçin</span>
                        </h1>
                        <p className="text-gray-400 text-lg">Davam etmək üçün aşağıdakı seçimlərdən birinə klikləyin.</p>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        {subCategories.map((sub, index) => (
                            <div 
                                key={index}
                                onClick={() => setSelectedSubCat(sub)}
                                className="group relative h-48 md:h-64 rounded-3xl overflow-hidden cursor-pointer border border-white/10 hover:border-gaming-neon transition-all duration-300 shadow-2xl"
                            >
                                {/* Background Image with Blur */}
                                <div className="absolute inset-0">
                                    <img 
                                        src={category.image} 
                                        alt={sub} 
                                        className="w-full h-full object-cover opacity-60 group-hover:scale-105 transition-transform duration-700 filter blur-sm group-hover:blur-0" 
                                    />
                                    <div className="absolute inset-0 bg-gradient-to-t from-black via-black/50 to-transparent"></div>
                                </div>

                                {/* Content */}
                                <div className="absolute inset-0 flex flex-col justify-end p-8">
                                    <div className="transform translate-y-2 group-hover:translate-y-0 transition-transform duration-300">
                                        <div className="flex items-center gap-3 mb-2">
                                            <span className="bg-gaming-neon text-black text-xs font-bold px-2 py-1 rounded uppercase tracking-wider">Seçim {index + 1}</span>
                                        </div>
                                        <h2 className="text-2xl md:text-4xl font-black text-white uppercase italic leading-none mb-2 group-hover:text-primary transition-colors">
                                            {sub}
                                        </h2>
                                        <p className="text-gray-400 text-sm opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex items-center gap-1">
                                            Məhsullara bax <ChevronRight className="w-4 h-4"/>
                                        </p>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* STEP 3: PRODUCTS VIEW */}
            {!showSubCategorySelection && (
                <div className="animate-fade-in">

                    {/* Header Banner (Compact) */}
                    <div className="relative rounded-2xl overflow-hidden mb-8 h-40 border border-gray-800 shadow-lg group">
                        {category.image && (
                            <img src={category.image} className="w-full h-full object-cover opacity-40" alt={category.name} />
                        )}
                        <div className="absolute inset-0 bg-gradient-to-r from-black via-black/80 to-transparent flex items-center p-8">
                             <div>
                                 <h1 className="text-2xl md:text-4xl font-black text-white uppercase italic mb-1">
                                     {selectedSubCat || category.name}
                                 </h1>
                                 <p className="text-gray-400 text-sm">
                                    <span className="text-gaming-neon font-bold">{filteredProducts.length}</span> məhsul tapıldı
                                 </p>
                             </div>
                        </div>
                    </div>

                    {/* Toolbar: Search & Sort */}
                    <div className="bg-gaming-card border border-gray-800 rounded-2xl p-4 mb-8 sticky top-24 z-30 shadow-xl backdrop-blur-md bg-opacity-90">
                        <div className="flex flex-col md:flex-row gap-4 justify-between">
                            {/* Search */}
                            <div className="relative flex-1">
                                <Search className="absolute left-3 top-3.5 text-gray-500 w-5 h-5" />
                                <input 
                                    type="text" 
                                    placeholder="Məhsul axtar..."
                                    className="w-full bg-slate-900 border border-gray-700 rounded-xl pl-10 pr-4 py-3 text-white focus:border-gaming-neon focus:ring-1 focus:ring-gaming-neon outline-none transition-all placeholder-gray-500"
                                    value={search}
                                    onChange={e => setSearch(e.target.value)}
                                />
                            </div>

                            {/* Sort Dropdown */}
                            <div className="relative min-w-[200px]">
                                <div className="absolute left-3 top-3.5 pointer-events-none">
                                    <ArrowDownUp className="w-5 h-5 text-gray-500" />
                                </div>
                                <select 
                                    className="w-full appearance-none bg-slate-900 border border-gray-700 rounded-xl pl-10 pr-8 py-3 text-white focus:border-gaming-neon outline-none cursor-pointer"
                                    value={sortOption}
                                    onChange={(e) => setSortOption(e.target.value as any)}
                                >
                                    <option value="default">Sıralama: Varsayılan</option>
                                    <option value="price-asc">Qiymət: Ucuzdan Bahaya</option>
                                    <option value="price-desc">Qiymət: Bahadan Ucuza</option>
                                    <option value="name-asc">Ad: A-Z</option>
                                </select>
                                <div className="absolute right-3 top-4 pointer-events-none">
                                    <Filter className="w-4 h-4 text-gray-500" />
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Product Grid */}
                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                        {filteredProducts.map(product => (
                            <ProductCard key={product.id} product={product} />
                        ))}
                    </div>

                    {/* Empty State */}
                    {filteredProducts.length === 0 && (
                        <div className="text-center py-20 bg-slate-900/30 rounded-3xl border border-dashed border-gray-800">
                            <div className="bg-slate-800 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-4">
                                <Search className="w-8 h-8 text-gray-500"/>
                            </div>
                            <h3 className="text-xl font-bold text-white mb-2">Nəticə Tapılmadı</h3>
                            <p className="text-gray-500">Bu kateqoriyada hələ məhsul yoxdur və ya axtarışa uyğun gəlmir.</p>
                            <button onClick={() => setSearch('')} className="mt-4 text-gaming-neon font-bold hover:underline">Axtarışı Təmizlə</button>
                        </div>
                    )}
                </div>
            )}
        </div>
    </div>
  );
};

export default CategoryPage;

import React, { useState } from 'react';
import { ShoppingCart, X, Trash2, Plus, Minus, ArrowRight, CreditCard, Wallet, Upload } from 'lucide-react';
import { useApp } from '../store';
import { useNavigate } from 'react-router-dom';

const CartWidget = () => {
  const { cart, updateCartQuantity, removeFromCart, isCartOpen, openCart, closeCart, placeOrder, paymentMethods, user, isAuthenticated } = useApp();
  const navigate = useNavigate();
  const [checkoutStep, setCheckoutStep] = useState<'cart' | 'payment'>('cart');
  const [selectedMethod, setSelectedMethod] = useState<string | 'BALANCE' | null>(null);
  const [receiptFile, setReceiptFile] = useState<File | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const subTotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  const handleCheckout = async () => {
     if(!isAuthenticated) {
         closeCart();
         navigate('/auth');
         return;
     }

     if(!selectedMethod) return;
     if (selectedMethod !== 'BALANCE' && !receiptFile) {
         alert("Zəhmət olmasa qəbz yükləyin.");
         return;
     }

     setIsSubmitting(true);
     const success = await placeOrder(selectedMethod, receiptFile || undefined);
     setIsSubmitting(false);

     if (success) {
        setCheckoutStep('cart');
        setSelectedMethod(null);
        setReceiptFile(null);
        closeCart();
        navigate('/profile'); 
     }
  };

  const reset = () => {
      setCheckoutStep('cart');
      setSelectedMethod(null);
      setReceiptFile(null);
      closeCart();
  }

  return (
    <>
      {/* Floating Trigger Button (Hidden on Mobile, Visible on Desktop) */}
      {/* Positioned at right-24 to sit left of the ChatWidget which is usually at right-6 */}
      <button 
        onClick={openCart}
        className="hidden md:flex items-center justify-center fixed bottom-6 right-24 z-50 bg-gradient-to-tr from-primary to-secondary w-16 h-16 rounded-full shadow-[0_0_20px_rgba(139,92,246,0.5)] hover:scale-110 transition-transform active:scale-95 group"
      >
        <ShoppingCart className="w-8 h-8 text-white" />
        {cart.length > 0 && (
            <span className="absolute -top-1 -right-1 w-6 h-6 bg-red-500 text-white text-xs font-bold rounded-full flex items-center justify-center border-2 border-[#0F1115] animate-bounce">
                {cart.length}
            </span>
        )}
      </button>

      {/* Backdrop - High Z-index to cover BottomNav on mobile */}
      {isCartOpen && (
        <div className="fixed inset-0 bg-black/80 z-[100] backdrop-blur-sm transition-opacity" onClick={reset} />
      )}

      {/* Drawer - Z-index 101 to be above backdrop */}
      <div className={`fixed top-0 right-0 h-full w-full sm:w-[420px] bg-surface/95 border-l border-white/10 z-[101] transform transition-transform duration-300 ease-out shadow-2xl flex flex-col backdrop-blur-xl ${isCartOpen ? 'translate-x-0' : 'translate-x-full'}`}>

         {/* Header */}
         <div className="p-6 border-b border-white/5 flex justify-between items-center bg-black/20">
            <h2 className="text-xl font-bold text-white flex items-center gap-3">
                {checkoutStep === 'cart' ? 'Səbətiniz' : 'Ödəniş'}
                {checkoutStep === 'cart' && <span className="bg-primary/20 text-primary text-xs px-2 py-1 rounded-full">{cart.length}</span>}
            </h2>
            <button onClick={reset} className="text-gray-400 hover:text-white p-2 hover:bg-white/5 rounded-full"><X /></button>
         </div>

         {/* Items */}
         <div className="flex-1 overflow-y-auto p-6 space-y-4">
            {cart.length === 0 ? (
                <div className="flex flex-col items-center justify-center h-full text-gray-500 space-y-4">
                    <div className="w-24 h-24 bg-surfaceHighlight rounded-full flex items-center justify-center mb-2">
                        <ShoppingCart className="w-10 h-10 opacity-30" />
                    </div>
                    <p className="font-medium text-lg">Səbətiniz boşdur</p>
                    <button onClick={reset} className="text-primary hover:text-white transition-colors">Alış-verişə davam et</button>
                </div>
            ) : checkoutStep === 'cart' ? (
                cart.map((item, index) => (
                    <div key={index} className="flex gap-4 p-4 rounded-2xl bg-surfaceHighlight/50 border border-white/5 hover:border-primary/30 transition-colors group">
                        <div className="w-20 h-20 rounded-xl overflow-hidden bg-black/50 shrink-0">
                            <img src={item.image} className="w-full h-full object-cover group-hover:scale-105 transition-transform" alt={item.title} />
                        </div>
                        <div className="flex-1 flex flex-col justify-between">
                            <div>
                                <h4 className="font-bold text-white text-sm line-clamp-1">{item.title}</h4>
                                {item.userInput && <p className="text-xs text-gray-400 mt-1">{item.userInput}</p>}
                            </div>

                            <div className="flex items-center justify-between mt-3">
                                <div className="text-white font-bold">{item.price.toFixed(2)} <span className="text-primary text-xs">₼</span></div>

                                <div className="flex items-center gap-3">
                                    <div className="flex items-center bg-black/30 rounded-lg p-0.5">
                                        <button onClick={() => updateCartQuantity(index, -1)} className="p-1.5 text-gray-400 hover:text-white"><Minus className="w-3 h-3"/></button>
                                        <span className="text-xs font-bold w-6 text-center text-white">{item.quantity}</span>
                                        <button onClick={() => updateCartQuantity(index, 1)} className="p-1.5 text-gray-400 hover:text-white"><Plus className="w-3 h-3"/></button>
                                    </div>
                                    <button onClick={() => removeFromCart(index)} className="text-gray-500 hover:text-red-500 transition-colors"><Trash2 className="w-4 h-4"/></button>
                                </div>
                            </div>
                        </div>
                    </div>
                ))
            ) : (
                <div className="space-y-6 animate-fade-in">
                    <div>
                        <h3 className="text-gray-400 uppercase text-xs font-bold mb-3">Ödəniş Metodu</h3>
                        <div className="space-y-2">
                            <button
                                onClick={() => setSelectedMethod('BALANCE')}
                                className={`w-full p-3 rounded-xl border flex items-center justify-between gap-2 transition-all text-sm text-left
                                    ${selectedMethod === 'BALANCE' 
                                    ? 'border-gaming-neon bg-gaming-neon/10' 
                                    : 'border-white/10 bg-slate-900 hover:bg-white/5'}`}
                            >
                                <div className="flex items-center gap-3">
                                    <div className="bg-black/40 p-2 rounded-lg"><Wallet className="w-4 h-4 text-purple-400" /></div>
                                    <span className="text-white font-bold">Balansdan Ödə</span>
                                </div>
                                <span className="text-gray-400 text-xs">{user?.balance.toFixed(2)} ₼</span>
                            </button>

                            {paymentMethods.filter(pm => pm.isActive).map(pm => (
                                <button
                                    key={pm.id}
                                    onClick={() => setSelectedMethod(pm.id)}
                                    className={`w-full p-3 rounded-xl border flex items-center gap-3 transition-all text-sm text-left
                                        ${selectedMethod === pm.id 
                                        ? 'border-gaming-neon bg-gaming-neon/10' 
                                        : 'border-white/10 bg-slate-900 hover:bg-white/5'}`}
                                >
                                    <div className="bg-black/40 p-2 rounded-lg"><CreditCard className="w-4 h-4 text-gray-400" /></div>
                                    <span className="text-white font-bold">{pm.name}</span>
                                </button>
                            ))}
                        </div>
                    </div>

                    {selectedMethod && selectedMethod !== 'BALANCE' && (
                        <div className="animate-fade-in">
                            <div className="bg-slate-900 p-4 rounded-xl text-sm border-l-4 border-primary mb-4">
                                <p className="text-gray-400 text-xs uppercase font-bold mb-1">Hesab:</p>
                                <p className="font-mono text-white mb-2">{paymentMethods.find(p=>p.id===selectedMethod)?.details}</p>
                                <p className="text-xs text-gray-500">{paymentMethods.find(p=>p.id===selectedMethod)?.instructions}</p>
                            </div>

                            <div className="relative border-2 border-dashed border-white/20 rounded-xl p-6 hover:bg-white/5 transition-colors text-center cursor-pointer">
                                <input type="file" accept="image/*" onChange={(e) => e.target.files && setReceiptFile(e.target.files[0])} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" />
                                <Upload className="w-6 h-6 text-gray-400 mx-auto mb-2" />
                                <p className="text-xs text-gray-300 font-bold">
                                    {receiptFile ? <span className="text-green-400">{receiptFile.name}</span> : "Qəbz yüklə"}
                                </p>
                            </div>
                        </div>
                    )}
                </div>
            )}
         </div>

         {/* Footer */}
         <div className="p-6 border-t border-white/5 bg-black/20">
            <div className="flex justify-between mb-6">
                <span className="text-gray-400">Cəmi Məbləğ</span>
                <span className="text-2xl font-bold text-white">{subTotal.toFixed(2)} <span className="text-primary">₼</span></span>
            </div>

            {checkoutStep === 'cart' ? (
                <button 
                    onClick={() => setCheckoutStep('payment')}
                    className="w-full bg-white text-black font-bold py-4 rounded-xl hover:bg-gray-200 transition-all flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed shadow-[0_0_20px_rgba(255,255,255,0.1)]"
                    disabled={cart.length === 0}
                >
                    Sifarişi Rəsmiləşdir <ArrowRight className="w-5 h-5" />
                </button>
            ) : (
                <div className="flex gap-2">
                    <button onClick={() => setCheckoutStep('cart')} className="px-4 py-4 rounded-xl bg-white/10 hover:bg-white/20 text-white font-bold">Geri</button>
                    <button 
                        onClick={handleCheckout}
                        disabled={!selectedMethod || (selectedMethod !== 'BALANCE' && !receiptFile) || isSubmitting}
                        className="flex-1 bg-green-600 text-white font-bold py-4 rounded-xl hover:bg-green-500 transition-all flex items-center justify-center gap-2 disabled:opacity-50"
                    >
                        {isSubmitting ? '...' : 'Təsdiqlə'} <ArrowRight className="w-5 h-5" />
                    </button>
                </div>
            )}
         </div>
      </div>
    </>
  );
};

export default CartWidget;
